use serde_json;

pub fn validate_json_structure(json_string: &str, expected_structure: HashMap<&str, &str>) -> bool {
    let expected_structure: serde_json::Value = serde_json::from_str(expected_structure.into_iter().map(|(k, v)| serde_json::json!({k: v})).collect::<Vec<_>>()[0].as_object().unwrap()).unwrap();

    let actual_structure: serde_json::Value = serde_json::from_str(json_string).unwrap();

    if actual_structure.is_object() && expected_structure.is_object() {
        let actual_object = actual_structure.as_object().unwrap();
        let expected_object = expected_structure.as_object().unwrap();

        for (key, value) in actual_object {
            if expected_object.contains_key(key) {
                if value != expected_structure.get(key).unwrap() {
                    return false;
                }
            } else {
                return false;
            }
        }
    } else if actual_structure.is_array() && expected_structure.is_array() {
        let actual_array = actual_structure.as_array().unwrap();
        let expected_array = expected_structure.as_array().unwrap();

        if actual_array.len() != expected_array.len() {
            return false;
        }

        for (index, value) in actual_array.iter().enumerate() {
            if expected_array.get(index).unwrap().as_str().unwrap() != value.as_str().unwrap() {
                return false;
            }
        }
    } else {
        return false;
    }

    true
}
