/// Merges a list of intervals into a new list containing non-overlapping merged intervals.
///
/// The function takes a vector of tuples, where each tuple represents an interval with a start and end value.
/// It merges overlapping intervals and returns a new vector containing only the non-overlapping merged intervals.
///
/// Each interval returned is formatted with the minimum start and maximum end of any overlapping intervals.
///
/// # Example
///
/// ```
/// let intervals = [(1, 3), (2, 6), (8, 10), (15, 18)];
/// let merged = merge_intervals(intervals);
/// assert_eq!(merged, [(1, 6), (8, 10), (15, 18)]);
/// ```rust
///
/// # Panics
///
/// The function will panic if the input vector is empty.
pub fn merge_intervals(intervals: Vec<(i32, i32)>) -> Vec<(i32, i32)> {
    if intervals.is_empty() {
        panic!("Input vector is empty");
    }

    intervals.into_iter()
        .map(|interval| (interval.0, interval.1))
        .collect::<Vec<_>>()
        .into_iter()
        .fold(vec![], |mut merged, current| {
            let last_merged = *merged.last().unwrap_or(&current);
            if current.0 <= last_merged.1 {
                merged.pop();
                merged.push((last_merged.0, current.1.max(last_merged.1)));
            } else {
                merged.push(current);
            }
            merged
        })
}
