#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char* expandTabs(const char* inputString, int tabSize) {
    int length = strlen(inputString) + 1;
    char* expandedString = malloc(length * sizeof(char));

    for (int i = 0; inputString[i] != '\0'; ++i) {
        if (inputString[i] == '\t') {
            int numSpaces = tabSize * (inputString[i + 1] - '0');
            for (int j = 0; j < numSpaces; ++j) {
                expandedString[length - 1 - j] = ' ';
            }
            i += numSpaces - 1;
        } else {
            expandedString[length - 1 - i] = inputString[i];
        }
    }

    return expandedString;
}
