import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.*;

public class Main {

    public static void sortByValueAndExport(Map<Integer, String> itemMap, int threshold) {
        // Sort the map entries
        List<Map.Entry<Integer, String>> sortedEntries = new ArrayList<>(itemMap.entrySet());
        sortedEntries.sort((o1, o2) -> {
            int value1 = Integer.parseInt(o1.getValue());
            int value2 = Integer.parseInt(o2.getValue());
            if (value1 > threshold && value2 > threshold) {
                return o1.getKey().compareTo(o2.getKey());
            } else if (value1 > threshold) {
                return -1;
            } else if (value2 > threshold) {
                return 1;
            } else {
                return o1.getValue().compareTo(o2.getValue());
            }
        });

        // Write the filtered and sorted entries to a CSV file
        try (PrintWriter writer = new PrintWriter(new FileWriter("filteredItems.csv"))) {
            writer.println("Key,Value");
            for (Map.Entry<Integer, String> entry : sortedEntries) {
                if (Integer.parseInt(entry.getValue()) > threshold) {
                    writer.println(entry.getKey() + "," + entry.getValue());
                }
            }
        } catch (IOException e) {
            System.err.println("Error writing to file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        Map<Integer, String> itemMap = new HashMap<>();
        itemMap.put(3, "10");
        itemMap.put(2, "20");
        itemMap.put(1, "30");
        itemMap.put(4, "40");
        sortByValueAndExport(itemMap, 20);
    }
}
